          CREATE OR REPLACE FUNCTION public.exec_sql(query TEXT)
          RETURNS VOID LANGUAGE plpgsql SECURITY DEFINER AS $$ BEGIN EXECUTE query; END; $$;
        `
      });

      if (e3) {
